from flask import Flask, request, Response, jsonify
from prometheus_client import Counter, Histogram, Gauge, generate_latest, CONTENT_TYPE_LATEST
import time

app = Flask(__name__)

REQUEST_COUNT = Counter(
    "http_requests_total",
    "Total HTTP requests",
    ["method", "endpoint", "status_code", "user_id", "api_key"]
)

REQUEST_LATENCY = Histogram(
    "http_request_duration_seconds",
    "HTTP request latency in seconds",
    ["method", "endpoint", "user_id", "api_key"]
)

REQUEST_BODY_SIZE = Gauge(
    "http_request_body_bytes",
    "HTTP request body size in bytes",
    ["method", "endpoint", "user_id", "api_key", "request_body"]
)

@app.before_request
def before_request():
    request._start_time = time.time()

@app.after_request
def after_request(response):
    duration = time.time() - getattr(request, "_start_time", time.time())
    user_id = request.headers.get("X-User-Id", "anonymous")
    api_key = request.headers.get("X-API-Key", "missing")
    endpoint = request.path
    method = request.method
    status_code = str(response.status_code)
    request_body = request.get_data(as_text=True) if request.get_data() else ""

    REQUEST_COUNT.labels(
        method=method,
        endpoint=endpoint,
        status_code=status_code,
        user_id=user_id,
        api_key=api_key
    ).inc()

    REQUEST_LATENCY.labels(
        method=method,
        endpoint=endpoint,
        user_id=user_id,
        api_key=api_key
    ).observe(duration)

    REQUEST_BODY_SIZE.labels(
        method=method,
        endpoint=endpoint,
        user_id=user_id,
        api_key=api_key,
        request_body=request_body
    ).set(len(request.get_data() or b""))

    return response

@app.route("/metrics")
def metrics():
    return Response(generate_latest(), mimetype=CONTENT_TYPE_LATEST)

@app.route("/api/hello", methods=["GET", "POST"])
def hello():
    user_id = request.headers.get("X-User-Id", "anonymous")
    return jsonify({"message": "hello", "user_id": user_id})

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)